  ('heelevel3-5ff21eeb-moex-00144', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲以電話詢問乙書店有無甲欲購買之A書，乙表示「有」，甲即以市價新臺幣500元與乙訂立A書買 賣契約，並請乙保留該書，乙請甲可隨時到店裡拿書。數日後，甲至乙書店取書時，乙遍尋不著 該書。下列敘述，何者正確？', '["乙所負交付書籍之債務為有確定期限之債務", "甲赴書店而未能取得該書時，乙即負遲延責任", "甲請求交付書籍僅有催告效力，乙尚不負遲延責任", "甲欲購書籍如為種類物，甲不得解除契約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00145', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲駕駛計程車載客人乙，途中不慎撞傷路人丙，導致丙住院支出醫療費、看護費等新臺幣10萬元。 丙請求甲、乙二人連帶負損害賠償責任，下列敘述，何者正確？', '["甲是乙之受僱人，乙應與甲連帶負損害賠償責任", "甲是乙之承攬人，乙原則上不須負損害賠償責任", "甲是乙之受任人，乙原則上不須負損害賠償責任", "甲客觀上是為乙服勞務之人，故乙必須負損害賠償責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00146', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '出租人甲與承租人乙訂立A車租賃契約，於下列何種情形，乙有權占有A車？', '["甲交付A車於乙使用", "租期屆滿後，乙拒絕返還", "租賃無效", "乙自行占有A車"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00147', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲將其所有之鑽錶寄託於乙處。乙以自己名義，出售並交付於不知情且無重大過失之丙。下列敘 述，何者正確？', '["甲得隨時向丙請求返還鑽錶", "甲僅得於2年內向丙請求返還鑽錶", "甲於償還丙支付之價金後，得向丙請求返還鑽錶，甲所受損害再向乙請求", "甲不得向丙請求返還鑽錶，甲所受損害僅得向乙請求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00148', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲男、乙女於民國110年5月間結婚，結婚後依法約定採分別財產制。下列敘述，何者正確？', '["甲、乙之一方在婚姻關係存續當中，就其婚後財產所為之無償行為，有害及他方之剩餘財產差 額分配請求權者，他方得於知有撤銷原因時起1年間，或自行為時起2年內，聲請法院撤銷上開 無償行為", "甲、乙財產制關係消滅時，其夫妻現存之婚後財產，應平均分配。平均分配顯失公平者，法院 得調整或免除其分配額", "甲、乙之一方以自己財產清償他方之債務時，雖於婚姻關係存續中，亦得請求他方償還", "甲、乙之一方依法應給付家庭生活費用而不給付時，法院因他方之請求，得宣告改用共同財產制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00149', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '關於父母對未成年子女親權之行使與禁止，下列敘述，何者正確？', '["未成年子女之特有財產，父母應以家庭生活之共同利益，而使用、收益、處分之。但子女已滿 16歲者，應得其書面同意", "父母之一方濫用其對於子女之權利時，法院得依他方、未成年子女、主管機關或其他利害關係 人之請求，為子女之利益，宣告停止其權利之全部或一部", "未成年子女之特有財產，由父母共同管理。但父母分居、或養子女與養父母合意終止收養經撤 銷者，不在此限", "父母未共同生活達6個月以上時，關於未成年子女之會面交往權之行使，父母、祖父母或社福機 構均得聲請法院酌定之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00150', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲重男輕女，因子丁留學美國，將其財產新臺幣（下同）1,000萬元贈與丁，完全不顧及平日照顧 其生活起居之妻乙及女丙之感受。1年後，甲死亡，另遺有財產600萬元，丙得繼承多少財產？', '["1,000萬元", "500萬元", "200萬元", "125萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00151', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'essay', '欠稅之納稅義務人，得在一定條件下被限制出境，為我國租稅保全程序的
